import sys
from functools import reduce

class Solution:
   def solve(self, A, B):
      n = len(A)
      m = len(B)
      if n > m:
         return "0001" # return a default value

      A.sort(reverse=True)
      i, j = 0, n-1

      while i <= j:
         if A[i] > B[j]:
            A[j] -= A[i]
            A[i] = max(A[i] - B[j], 0)
            i += 1
         else:
            j -= 1

      return ''.join(map(str, A == 0))

def main():
   T = int(sys.stdin.readline().strip())
   for i in range(T):
      A = list(map(int, sys.stdin.readline().strip().split(' ')))
      B = list(map(int, sys.stdin.readline().strip().split(' ')))
      s = Solution()
      print(s.solve(A, B))

if __name__ == '__main__':
   main()

